14	    const result = processScenario({
15	      customer: { yearsWithMHPCO: 0 },
16	      steps: [{
17	        op: "quote" as const,
18	        items: [{ type: "sword", material: "steel", enchantment: 0, cursed: false }],
19	      }],
20	    });
21	    expect(result).toEqual({ results: [{ premium: 115 }] });
22	  });
23	  it.todo("single amulet returns premium of 71 G (60 base + 6 first + 5 fee)");
24	  it.todo("single staff returns premium of 93 G (80 base + 8 first + 5 fee)");
25	  it.todo("single potion returns premium of 49 G (40 base + 4 first + 5 fee)");
26	  it.todo("single rune component returns premium of 33 G (25 base + 2.5 first rounded up to 3 + 5 fee)");
27	  it.todo("two runes returns premium of 61 G (50 base + 5 first + 5 fee, rounded up)");
28	
29	  // === QUOTE: Component block pricing ===
30	  it.todo("3 alike runes returns block premium (60 base + 6 first + 5 fee = 71 G)");
31	  it.todo("4 runes returns non-block premium (100 base + 10 first + 5 fee = 115 G)");
32	  it.todo("2 runes + 1 moonstone returns 75 base (no block, different types)");
33	  it.todo("3 runes + 3 moonstones returns 120 base (two separate blocks)");
34	
35	  // === QUOTE: Item-specific modifiers ===
36	  it.todo("cursed sword adds 50% surcharge to sword base premium");
37	  it.todo("highly enchanted sword (enchantment >= 5) adds 30% surcharge to sword base premium");
38	  it.todo("cursed and highly enchanted sword has both surcharges applied");
39	  it.todo("enchantment 4 does not trigger high-enchantment surcharge");
40	
41	  // === QUOTE: Policy-wide modifiers ===
42	  it.todo("long-standing customer (>= 2 years) receives 20% loyalty discount on policy base");
43	  it.todo("customer with exactly 2 years qualifies for loyalty discount");
44	  it.todo("follow-up contract (second quote) receives 15% discount on policy base");
45	
46	  // === QUOTE: Multi-item policies ===
47	  it.todo("policy with cursed sword and plain amulet applies curse surcharge only to sword");
48	  it.todo("policy with multiple items sums item base premiums before policy-wide modifiers");
49	
50	  // === QUOTE: Integration - modifier stacking ===
51	  it.todo("newcomer with cursed sword: 100 + 50 curse + 10 first + 5 fee = 165 G");
52	  it.todo("long-standing customer second contract cursed enchanted sword: 155 + 5 fee = 160 G");
53	
54	  // === QUOTE: Rounding ===
55	  it.todo("premium rounds up (in MHPCO's favor) to whole G");
56	
57	  // === CLAIM: Basic payout ===
58	  it.todo("regular sword damage 500 G returns payout 400 G (full reimbursement minus 100 deductible)");
59	  it.todo("component damage 200 G returns payout 100 G (full minus 100 deductible)");
60	
61	  // === CLAIM: Special clauses ===
62	  it.todo("enchantment >= 8 reimburses at 50% of damage then deductible");
63	  it.todo("dragon material fully reimburses then deductible");
64	  it.todo("dragon material with enchantment >= 8: 50% wins then deductible");
65	  it.todo("dragon material with enchantment < 8: full reimbursement then deductible");
66	
67	  // === CLAIM: Cap ===
68	  it.todo("policy cap is 2x insurance sum");
69	  it.todo("successive claims exhaust cap: second claim reduced to remaining cap");
70	
71	  // === CLAIM: Multiple items in one event ===
72	  it.todo("multiple damaged items each have their own deductible");
73	
74	  // === CLAIM: Validation ===
75	  it.todo("damage to item not in policy rejects the claim");
76	  it.todo("more damage entries of a type than policy covers rejects the claim");
77	  it.todo("negative damage amount rejects the claim");
78	
79	  // === QUOTE: Validation ===
80	  it.todo("unknown item type in quote rejects with error");
81	
82	  // === CLI integration ===
83	  it.todo("CLI reads scenario from stdin and writes results to stdout");
84	  it.todo("CLI exits with non-zero status on error and writes to stderr");
