1	const PROCESSING_FEE = 5;
2	
3	const BASE_PREMIUMS: Record<string, number> = {
4	  sword: 100,
5	};
6	
7	export function processScenario(scenario: any): unknown {
8	  const results = scenario.steps.map((step: any) => {
9	    if (step.op === "quote") {
10	      const items = step.items || [];
11	      let policyBase = 0;
12	      for (const item of items) {
13	        policyBase += BASE_PREMIUMS[item.type] || 0;
14	      }
15	      const firstInsurance = policyBase * 0.1;
16	      const premium = Math.ceil(policyBase + firstInsurance + PROCESSING_FEE);
17	      return { premium };
18	    }
19	  });
20	  return { results };
21	}
